// talks/vector-search-visualised/facenet-learning.js
// Staged visualisation: a network learns what "similar" means.
//   stage 0  untrained — faces land in a structureless scatter
//   stage 1  training  — points stream into identity clusters, churning
//   stage 2  trained   — clusters resolve, each anchored by a face
//   stage 3  generalises — a held-out photo lands in the right cluster
// Presenter-stepped: advance()/retreat() consume the arrow keys.

import * as THREE from 'three';

/* FACES_START — generated by data/make_facenet_module.js, do not edit by hand */
const FACES = [
  { color: "#5b86e8", dataUri: "data:image/jpeg;base64," },
  { color: "#e8a14b", dataUri: "data:image/jpeg;base64," },
  { color: "#6dd6a0", dataUri: "data:image/jpeg;base64," },
  { color: "#e87da8", dataUri: "data:image/jpeg;base64," },
  { color: "#a98de8", dataUri: "data:image/jpeg;base64," }
];
/* FACES_END */

const DEFAULTS = { background: '#070d18', speed: 1 };

const MAX_STAGE = 3;
const LERP = 0.09; // stage easing
const POINTS_PER_IDENTITY = 14;
const JITTER = 0.4; // cluster radius
const NEWCOMER_ID = 2; // identity whose held-out photo arrives at stage 3

// One cluster centre per identity. Length MUST equal FACES.length.
const CLUSTERS = [
  [-0.3, 1.2, 0.2],
  [2.6, 1.45, -0.5],
  [4.3, -0.1, 0.4],
  [0.7, -1.5, 0.5],
  [3.4, -1.65, -0.3],
];

const NET_X = -3.9; // network gateway x
const SPAWN_X = -7.0; // newcomer enters from off-screen left
const SCENE_X = 1.9; // camera + caption horizontal centre

// Training churn: 0 below stage 0.35, ramps to 1 at stage 1, fades by stage 2.
function trainingEnergy(t) {
  if (t <= 0.35) return 0;
  if (t <= 1) return (t - 0.35) / 0.65;
  if (t <= 2) return 1 - (t - 1);
  return 0;
}

export default function init({ canvas, opts = {} }) {
  const cfg = { ...DEFAULTS, ...opts };
  // prefers-reduced-motion is intentionally not honoured: the staged
  // transitions are the teaching — a frozen frame would show nothing.

  const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  let w = canvas.clientWidth || canvas.width;
  let h = canvas.clientHeight || canvas.height;
  renderer.setSize(w, h, false);
  renderer.setClearColor(new THREE.Color(cfg.background), 1);

  const scene = new THREE.Scene();
  scene.fog = new THREE.Fog(new THREE.Color(cfg.background), 10, 22);

  const camera = new THREE.PerspectiveCamera(42, (w || 1) / (h || 1), 0.1, 100);
  camera.position.set(SCENE_X, 0, 9.9);
  camera.lookAt(SCENE_X, 0, 0);

  const group = new THREE.Group();
  scene.add(group);

  const disposables = []; // anything with a .dispose()

  // Soft circular sprite so points render as round dots.
  function discTexture() {
    const s = 64;
    const cv = document.createElement('canvas');
    cv.width = cv.height = s;
    const g = cv.getContext('2d');
    const grd = g.createRadialGradient(s / 2, s / 2, 0, s / 2, s / 2, s / 2);
    grd.addColorStop(0, 'rgba(255,255,255,1)');
    grd.addColorStop(0.5, 'rgba(255,255,255,1)');
    grd.addColorStop(1, 'rgba(255,255,255,0)');
    g.fillStyle = grd;
    g.fillRect(0, 0, s, s);
    const tex = new THREE.CanvasTexture(cv);
    disposables.push(tex);
    return tex;
  }
  const sprite = discTexture();

  // Small text label as a camera-facing sprite. Rendered at 2x so it stays
  // crisp when scaled up in the scene.
  function textSprite(text, color) {
    const dpi = 2;
    const pad = 12 * dpi;
    const cv = document.createElement('canvas');
    let ctx = cv.getContext('2d');
    const font = `600 ${30 * dpi}px Inter, system-ui, sans-serif`;
    ctx.font = font;
    const tw = Math.ceil(ctx.measureText(text).width);
    cv.width = tw + pad * 2;
    cv.height = 46 * dpi;
    ctx = cv.getContext('2d');
    ctx.font = font;
    ctx.fillStyle = color;
    ctx.textBaseline = 'middle';
    ctx.fillText(text, pad, cv.height / 2);
    const tex = new THREE.CanvasTexture(cv);
    tex.colorSpace = THREE.SRGBColorSpace;
    tex.minFilter = THREE.LinearFilter;
    tex.generateMipmaps = false;
    const mat = new THREE.SpriteMaterial({
      map: tex,
      transparent: true,
      depthWrite: false,
      depthTest: false,
    });
    const sp = new THREE.Sprite(mat);
    sp.scale.set((cv.width / cv.height) * 0.6, 0.6, 1);
    disposables.push(tex, mat);
    return sp;
  }

  const baseColors = FACES.map((f) => new THREE.Color(f.color));
  const centres = CLUSTERS.map((c) => new THREE.Vector3(c[0], c[1], c[2]));
  const untrained = new THREE.Color(0x55617d); // colourless "no identity known"

  // === layers ===
  const points = buildPoints();
  const network = buildNetwork();
  const thumbs = buildThumbnails();
  const links = buildLinks();
  const newcomer = buildNewcomer();
  const captions = buildCaptions();

  // === stage state ===
  let stage = 0;
  let targetStage = 0;
  let stageT = 0;

  let raf = 0;
  let last = performance.now();
  let elapsed = 0;
  function frame(now) {
    const dt = Math.min((now - last) / 1000, 0.05);
    last = now;
    const sdt = dt * cfg.speed;
    elapsed += sdt;

    const prev = stageT;
    stageT += (targetStage - stageT) * LERP;
    if (prev < 0.45 && stageT >= 0.45) network.triggerSweep(); // training begins

    const energy = trainingEnergy(stageT);
    points.update(stageT, energy, sdt, elapsed);
    links.update(energy, elapsed);
    network.update(stageT, sdt);
    thumbs.update(stageT);
    newcomer.update(stageT, sdt, elapsed);
    captions.update(stageT);

    renderer.render(scene, camera);
    raf = requestAnimationFrame(frame);
  }
  raf = requestAnimationFrame(frame);

  function onResize() {
    w = canvas.clientWidth || canvas.width;
    h = canvas.clientHeight || canvas.height;
    if (!w || !h) return;
    renderer.setSize(w, h, false);
    camera.aspect = w / h;
    camera.updateProjectionMatrix();
  }
  window.addEventListener('resize', onResize);

  // ---- layer: embedding space ----
  function buildPoints() {
    const count = FACES.length * POINTS_PER_IDENTITY;
    const total = count + 1; // final slot is the stage-3 newcomer
    const positions = new Float32Array(total * 3);
    const colors = new Float32Array(total * 3);
    const pool = [];

    for (let i = 0; i < count; i++) {
      const id = Math.floor(i / POINTS_PER_IDENTITY);
      const home = new THREE.Vector3(
        (Math.random() * 2 - 1) * JITTER,
        (Math.random() * 2 - 1) * JITTER,
        (Math.random() * 2 - 1) * JITTER,
      );
      const trained = centres[id].clone().add(home);
      const scatter = new THREE.Vector3(
        SCENE_X + (Math.random() * 2 - 1) * 3.2,
        (Math.random() * 2 - 1) * 2.1,
        (Math.random() * 2 - 1) * 0.85,
      );
      pool.push({ id, home, trained, scatter, pos: scatter.clone(), phase: Math.random() * Math.PI * 2 });
      scatter.toArray(positions, i * 3);
      untrained.toArray(colors, i * 3);
    }

    // Newcomer slot: parked off-screen and background-coloured until stage 3,
    // so it renders identically to a real cluster dot once it arrives.
    positions[count * 3] = SPAWN_X;
    new THREE.Color(cfg.background).toArray(colors, count * 3);

    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    const mat = new THREE.PointsMaterial({
      map: sprite,
      size: 0.38,
      sizeAttenuation: true,
      vertexColors: true,
      transparent: true,
      opacity: 0.97,
      depthWrite: false,
    });
    group.add(new THREE.Points(geo, mat));
    disposables.push(geo, mat);

    const target = new THREE.Vector3();
    const col = new THREE.Color();

    function update(st, energy, dt, elapsed) {
      // 0 = scattered, 1 = clustered; lags the stage so 1→2 still tightens.
      const k = THREE.MathUtils.smoothstep(st, 0, 1.7);
      const follow = Math.min(1, dt * 3.2);
      for (let i = 0; i < pool.length; i++) {
        const p = pool[i];
        target.lerpVectors(p.scatter, p.trained, k);
        target.x += Math.sin(elapsed * 0.5 + p.phase) * 0.1;
        target.y += Math.cos(elapsed * 0.43 + p.phase) * 0.1;
        target.z += Math.sin(elapsed * 0.37 + p.phase) * 0.08;
        if (energy > 0) {
          target.x += Math.sin(elapsed * 2.1 + p.phase * 1.7) * 0.16 * energy;
          target.y += Math.cos(elapsed * 1.9 + p.phase * 1.3) * 0.16 * energy;
        }
        p.pos.lerp(target, follow);
        p.pos.toArray(positions, i * 3);
        col.copy(untrained).lerp(baseColors[p.id], k);
        col.toArray(colors, i * 3);
      }
      geo.attributes.position.needsUpdate = true;
      geo.attributes.color.needsUpdate = true;
    }

    return { pool, update, geo, positions, colors, count };
  }

  // ---- layer: network gateway ----
  function buildNetwork() {
    const cols = 3;
    const rows = 5;
    const colGap = 0.36;
    const rowGap = 0.5;
    const nodePos = new Float32Array(cols * rows * 3);
    let k = 0;
    for (let c = 0; c < cols; c++) {
      for (let r = 0; r < rows; r++) {
        nodePos[k++] = NET_X + c * colGap;
        nodePos[k++] = (r - (rows - 1) / 2) * rowGap;
        nodePos[k++] = 0;
      }
    }
    const ngeo = new THREE.BufferGeometry();
    ngeo.setAttribute('position', new THREE.BufferAttribute(nodePos, 3));
    const nmat = new THREE.PointsMaterial({
      map: sprite,
      color: 0x6f93e8,
      size: 0.22,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.8,
      depthWrite: false,
    });
    group.add(new THREE.Points(ngeo, nmat));
    disposables.push(ngeo, nmat);

    const segs = [];
    for (let c = 0; c < cols - 1; c++) {
      for (let r1 = 0; r1 < rows; r1++) {
        for (let r2 = 0; r2 < rows; r2++) {
          segs.push(
            NET_X + c * colGap, (r1 - (rows - 1) / 2) * rowGap, 0,
            NET_X + (c + 1) * colGap, (r2 - (rows - 1) / 2) * rowGap, 0,
          );
        }
      }
    }
    const egeo = new THREE.BufferGeometry();
    egeo.setAttribute('position', new THREE.BufferAttribute(new Float32Array(segs), 3));
    const emat = new THREE.LineBasicMaterial({
      color: 0x5b86e8,
      transparent: true,
      opacity: 0.32,
      depthWrite: false,
    });
    group.add(new THREE.LineSegments(egeo, emat));
    disposables.push(egeo, emat);

    const label = textSprite('neural network', '#7f93c8');
    label.position.set(NET_X + colGap, -((rows - 1) / 2) * rowGap - 0.55, 0);
    label.scale.multiplyScalar(0.74);
    group.add(label);

    // Bright bar that sweeps the strip while an input is processed.
    const sweepMat = new THREE.SpriteMaterial({
      map: sprite,
      color: 0xbcd0ff,
      transparent: true,
      opacity: 0,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
    });
    const sweep = new THREE.Sprite(sweepMat);
    sweep.scale.set(0.6, rows * rowGap + 0.4, 1);
    sweep.position.set(NET_X, 0, 0.08);
    group.add(sweep);
    disposables.push(sweepMat);

    const SWEEP_DUR = 0.7;
    const sweepFrom = NET_X - 0.3;
    const sweepTo = NET_X + (cols - 1) * colGap + 0.3;
    let sweepT = SWEEP_DUR + 1; // start idle

    function update(st, dt) {
      // Network recedes to a backdrop once training is underway.
      const dim = 1 - 0.5 * THREE.MathUtils.smoothstep(st, 1, 2);
      nmat.opacity = 0.8 * dim;
      emat.opacity = 0.32 * dim;
      label.material.opacity = 0.85 * dim;
      if (sweepT < SWEEP_DUR) {
        sweepT += dt;
        const f = Math.min(1, sweepT / SWEEP_DUR);
        sweep.position.x = sweepFrom + (sweepTo - sweepFrom) * f;
        sweepMat.opacity = Math.sin(f * Math.PI) * 0.9;
      } else {
        sweepMat.opacity = 0;
      }
    }

    return { update, triggerSweep: () => { sweepT = 0; } };
  }

  // ---- layer: face thumbnails anchoring each cluster ----
  function buildThumbnails() {
    const loader = new THREE.TextureLoader();
    const faceGeo = new THREE.CircleGeometry(0.34, 48);
    disposables.push(faceGeo);
    const thumbs = [];
    FACES.forEach((face, id) => {
      const tex = loader.load(face.dataUri);
      tex.colorSpace = THREE.SRGBColorSpace;
      tex.minFilter = THREE.LinearFilter;
      tex.magFilter = THREE.LinearFilter;
      tex.generateMipmaps = false;
      const mat = new THREE.MeshBasicMaterial({
        map: tex,
        transparent: true,
        opacity: 0,
        depthWrite: false,
      });
      const mesh = new THREE.Mesh(faceGeo, mat);
      // Lifted clear above the cluster so the dot blob stays visible — the
      // face labels the cluster rather than hiding it.
      mesh.position.set(centres[id].x, centres[id].y + 0.68, centres[id].z + 0.3);
      mesh.visible = false;
      group.add(mesh);
      disposables.push(mat, tex);
      thumbs.push({ mesh, mat });
    });

    function update(st) {
      // Reveal the faces once the clusters have resolved.
      const op = THREE.MathUtils.smoothstep(st, 1.4, 2.05) * 0.98;
      for (const t of thumbs) {
        t.mat.opacity = op;
        t.mesh.visible = op > 0.01;
      }
    }

    return { update };
  }

  // ---- layer: stage-1 attraction links ----
  function buildLinks() {
    const COUNT = 7;
    const pool = points.pool;
    const pairs = [];
    const positions = new Float32Array(COUNT * 2 * 3);
    const colors = new Float32Array(COUNT * 2 * 3);
    for (let l = 0; l < COUNT; l++) {
      const id = (Math.random() * FACES.length) | 0;
      const base = id * POINTS_PER_IDENTITY;
      const a = (Math.random() * POINTS_PER_IDENTITY) | 0;
      let b = (Math.random() * POINTS_PER_IDENTITY) | 0;
      if (b === a) b = (b + 1) % POINTS_PER_IDENTITY;
      pairs.push([base + a, base + b]);
      baseColors[id].toArray(colors, l * 6);
      baseColors[id].toArray(colors, l * 6 + 3);
    }
    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
    const mat = new THREE.LineBasicMaterial({
      vertexColors: true,
      transparent: true,
      opacity: 0,
      depthWrite: false,
    });
    const lines = new THREE.LineSegments(geo, mat);
    lines.visible = false;
    group.add(lines);
    disposables.push(geo, mat);

    function update(energy, elapsed) {
      if (energy <= 0) {
        lines.visible = false;
        return;
      }
      lines.visible = true;
      for (let l = 0; l < COUNT; l++) {
        pool[pairs[l][0]].pos.toArray(positions, l * 6);
        pool[pairs[l][1]].pos.toArray(positions, l * 6 + 3);
      }
      geo.attributes.position.needsUpdate = true;
      mat.opacity = energy * 0.6 * (0.7 + 0.3 * Math.sin(elapsed * 3));
    }

    return { update };
  }

  // ---- layer: held-out photo (stage 3) ----
  // The newcomer is the final slot in the points buffer, so it renders
  // identically to a real cluster dot — it just flies in on stage 3.
  function buildNewcomer() {
    const { positions, colors, geo, count } = points;
    const off = count * 3;
    const idColor = baseColors[NEWCOMER_ID];
    const white = new THREE.Color(0xffffff);
    const bg = new THREE.Color(cfg.background);

    const spawn = new THREE.Vector3(SPAWN_X, centres[NEWCOMER_ID].y, 0);
    const netExit = new THREE.Vector3(NET_X + 0.85, centres[NEWCOMER_ID].y, 0);
    const landing = centres[NEWCOMER_ID].clone().add(new THREE.Vector3(0.16, 0.12, 0.1));
    const pos = new THREE.Vector3();
    const col = new THREE.Color();
    let prevG = 0;

    function write() {
      geo.attributes.position.needsUpdate = true;
      geo.attributes.color.needsUpdate = true;
    }

    function update(st) {
      const g = THREE.MathUtils.smoothstep(st, 2, 3);
      if (g <= 0.001) {
        if (prevG !== 0) {
          positions[off] = SPAWN_X;
          positions[off + 1] = 0;
          positions[off + 2] = 0;
          bg.toArray(colors, off);
          write();
          prevG = 0;
        }
        return;
      }
      if (prevG < 0.22 && g >= 0.22) network.triggerSweep(); // passing through
      prevG = g;

      if (g < 0.5) {
        pos.lerpVectors(spawn, netExit, THREE.MathUtils.smoothstep(g / 0.5, 0, 1));
      } else {
        pos.lerpVectors(netExit, landing, THREE.MathUtils.smoothstep((g - 0.5) / 0.5, 0, 1));
      }
      pos.toArray(positions, off);
      // White flash while travelling, settling to its identity colour on arrival.
      const settle = THREE.MathUtils.smoothstep(g, 0.8, 1);
      const flash = (1 - settle) * (0.5 + 0.5 * Math.sin(performance.now() * 0.009));
      col.copy(idColor).lerp(white, flash * 0.85);
      col.toArray(colors, off);
      write();
    }

    return { update };
  }

  // ---- layer: per-stage captions ----
  function buildCaptions() {
    const lines = [
      'Untrained — faces land in no particular order',
      'Training nudges each face toward others of the same person',
      'Trained — the same person’s faces now sit together',
      'A photo it’s never seen lands in the right place',
    ];
    const sprites = lines.map((text) => {
      const sp = textSprite(text, '#b8c6e8');
      sp.scale.multiplyScalar(0.62);
      sp.position.set(SCENE_X, -2.7, 1.2);
      sp.material.opacity = 0;
      group.add(sp);
      return sp;
    });

    function update(st) {
      for (let i = 0; i < sprites.length; i++) {
        const op = Math.max(0, 1 - Math.abs(st - i) / 0.5);
        sprites[i].material.opacity = op;
        sprites[i].visible = op > 0.01;
      }
    }

    return { update };
  }

  return {
    advance() {
      if (stage >= MAX_STAGE) return false;
      stage++;
      targetStage = stage;
      return true;
    },
    retreat() {
      if (stage <= 0) return false;
      stage--;
      targetStage = stage;
      return true;
    },
    dispose() {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', onResize);
      for (const d of disposables) d.dispose();
      renderer.dispose();
    },
  };
}
